<module id="fsm">
    <description>Mealy FSM detection circuit that detects the sequence '10011' in the input IN. Outputs MATCH=1 when the sequence is detected, and MATCH=0 otherwise.</description>
    <ports>
        <input id="IN">Input signal to the FSM.</input>
        <input id="CLK">Clock signal used for synchronous operation.</input>
        <input id="RST">Reset signal to initialize the FSM.</input>
        <output id="MATCH">Output signal indicating a match condition based on the FSM state.</output>
    </ports>
    <parameter_description>
        <state name="S0" value="0000">State S0</state>
        <state name="S1" value="0001">State S1</state>
        <state name="S2" value="0010">State S2</state>
        <state name="S3" value="0011">State S3</state>
        <state name="S4" value="0100">State S4</state>
        <state name="S5" value="0101">State S5</state>
    </parameter_description>
    <logic_description type="sequential_logic">
        <register id="current_state" width="4" initial_value="0000">Current state of the FSM.</register>
        <wire id="next_state" width="4">Next state of the FSM.</wire>
        <wire id="match_condition" width="1">Match condition signal.</wire>
    </logic_description>
    <implementation>
        // State transition logic
        always @(posedge CLK or negedge RST) begin
            if (!RST) begin
                current_state <= 4'b0000;
                MATCH <= 1'b0;
            end else begin
                case (current_state)
                    4'b0000: begin
                        if (IN == 1'b1) begin
                            next_state <= 4'b0001;
                            match_condition <= 1'b0;
                        end else begin
                            next_state <= 4'b0000;
                            match_condition <= 1'b0;
                        end
                    end
                    4'b0001: begin
                        if (IN == 1'b0) begin
                            next_state <= 4'b0010;
                            match_condition <= 1'b0;
                        end else begin
                            next_state <= 4'b0000;
                            match_condition <= 1'b0;
                        end
                    end
                    4'b0010: begin
                        if (IN == 1'b0) begin
                            next_state <= 4'b0011;
                            match_condition <= 1'b0;
                        end else begin
                            next_state <= 4'b0000;
                            match_condition <= 1'b0;
                        end
                    end
                    4'b0011: begin
                        if (IN == 1'b1) begin
                            next_state <= 4'b0100;
                            match_condition <= 1'b0;
                        end else begin
                            next_state <= 4'b0000;
                            match_condition <= 1'b0;
                        end
                    end
                    4'b0100: begin
                        if (IN == 1'b1) begin
                            next_state <= 4'b0101;
                            match_condition <= 1'b1;
                        end else begin
                            next_state <= 4'b0000;
                            match_condition <= 1'b0;
                        end
                    end
                    4'b0101: begin
                        if (IN == 1'b0) begin
                            next_state <= 4'b0000;
                            match_condition <= 1'b0;
                        end else begin
                            next_state <= 4'b0000;
                            match_condition <= 1'b0;
                        end
                    end
                    default: begin
                        next_state <= 4'b0000;
                        match_condition <= 1'b0;
                    end
                endcase
                current_state <= next_state;
                MATCH <= match_condition;
            end
        end
    </implementation>
</module>
```
